import scala.util.Random
import java.time.{Instant, Duration}
import java.util.concurrent.ConcurrentHashMap
import scala.collection.concurrent
import scala.jdk.CollectionConverters._

case class SessionToken(
  token: String,
  userId: String,
  createdAt: Instant,
  expiresAt: Instant,
  isActive: Boolean = true
)

case class ApiKey(
  key: String,
  secret: String,
  owner: String,
  createdAt: Instant,
  expiresAt: Option[Instant] = None,
  isActive: Boolean = true,
  scopes: Set[String] = Set.empty
)

trait TokenGenerator {
  def generateToken(length: Int = 32): String
  def generateHexToken(length: Int = 64): String
}

class DefaultTokenGenerator extends TokenGenerator {
  override def generateToken(length: Int = 32): String = {
    Random.alphanumeric.take(length).mkString
  }

  override def generateHexToken(length: Int = 64): String = {
    val bytes = new Array[Byte](length / 2)
    Random.nextBytes(bytes)
    bytes.map("%02x".format(_)).mkString
  }
}

trait SessionStore {
  def save(session: SessionToken): Unit
  def find(token: String): Option[SessionToken]
  def remove(token: String): Unit
  def removeExpired(): Int
  def findByUserId(userId: String): List[SessionToken]
}

class InMemorySessionStore extends SessionStore {
  private val sessions: concurrent.Map[String, SessionToken] =
    new ConcurrentHashMap[String, SessionToken]().asScala

  override def save(session: SessionToken): Unit = {
    sessions.put(session.token, session)
  }

  override def find(token: String): Option[SessionToken] = {
    sessions.get(token).filter(s => s.isActive && s.expiresAt.isAfter(Instant.now()))
  }

  override def remove(token: String): Unit = {
    sessions.remove(token)
  }

  override def removeExpired(): Int = {
    val now = Instant.now()
    val expiredTokens = sessions.filter { case (_, session) =>
      session.expiresAt.isBefore(now)
    }.keys.toList

    expiredTokens.foreach(sessions.remove)
    expiredTokens.size
  }

  override def findByUserId(userId: String): List[SessionToken] = {
    sessions.values.filter(_.userId == userId).toList
  }
}

trait ApiKeyStore {
  def save(apiKey: ApiKey): Unit
  def findByKey(key: String): Option[ApiKey]
  def revoke(key: String): Unit
  def findByOwner(owner: String): List[ApiKey]
}

class InMemoryApiKeyStore extends ApiKeyStore {
  private val apiKeys: concurrent.Map[String, ApiKey] =
    new ConcurrentHashMap[String, ApiKey]().asScala

  override def save(apiKey: ApiKey): Unit = {
    apiKeys.put(apiKey.key, apiKey)
  }

  override def findByKey(key: String): Option[ApiKey] = {
    apiKeys.get(key).filter { ak =>
      ak.isActive && ak.expiresAt.forall(_.isAfter(Instant.now()))
    }
  }

  override def revoke(key: String): Unit = {
    apiKeys.get(key).foreach { ak =>
      apiKeys.put(key, ak.copy(isActive = false))
    }
  }

  override def findByOwner(owner: String): List[ApiKey] = {
    apiKeys.values.filter(_.owner == owner).toList
  }
}

sealed trait TokenServiceError
case class SessionNotFound(token: String) extends TokenServiceError
case class SessionExpired(token: String) extends TokenServiceError
case class ApiKeyNotFound(key: String) extends TokenServiceError
case class ApiKeyRevoked(key: String) extends TokenServiceError
case class InvalidScope(scope: String) extends TokenServiceError

class TokenGenerationService(
  tokenGenerator: TokenGenerator = new DefaultTokenGenerator(),
  sessionStore: SessionStore = new InMemorySessionStore(),
  apiKeyStore: ApiKeyStore = new InMemoryApiKeyStore(),
  defaultSessionDuration: Duration = Duration.ofHours(24),
  maxSessionsPerUser: Int = 5
) {

  def createSession(userId: String, durationOverride: Option[Duration] = None): Either[TokenServiceError, SessionToken] = {
    // Enforce max sessions per user
    val existingSessions = sessionStore.findByUserId(userId)
    if (existingSessions.size >= maxSessionsPerUser) {
      // Remove the oldest session
      existingSessions
        .sortBy(_.createdAt)
        .headOption
        .foreach(s => sessionStore.remove(s.token))
    }

    val now = Instant.now()
    val duration = durationOverride.getOrElse(defaultSessionDuration)
    val session = SessionToken(
      token = tokenGenerator.generateToken(32),
      userId = userId,
      createdAt = now,
      expiresAt = now.plus(duration)
    )

    sessionStore.save(session)
    Right(session)
  }

  def validateSession(token: String): Either[TokenServiceError, SessionToken] = {
    sessionStore.find(token) match {
      case Some(session) if session.expiresAt.isAfter(Instant.now()) && session.isActive =>
        Right(session)
      case Some(session) if session.expiresAt.isBefore(Instant.now()) =>
        sessionStore.remove(token)
        Left(SessionExpired(token))
      case _ =>
        Left(SessionNotFound(token))
    }
  }

  def refreshSession(token: String, newDuration: Option[Duration] = None): Either[TokenServiceError, SessionToken] = {
    validateSession(token) match {
      case Right(existingSession) =>
        sessionStore.remove(token)
        val now = Instant.now()
        val duration = newDuration.getOrElse(defaultSessionDuration)
        val newSession = SessionToken(
          token = tokenGenerator.generateToken(32),
          userId = existingSession.userId,
          createdAt = now,
          expiresAt = now.plus(duration)
        )
        sessionStore.save(newSession)
        Right(newSession)
      case Left(error) =>
        Left(error)
    }
  }

  def invalidateSession(token: String): Either[TokenServiceError, Unit] = {
    sessionStore.find(token) match {
      case Some(_) =>
        sessionStore.remove(token)
        Right(())
      case None =>
        Left(SessionNotFound(token))
    }
  }

  def invalidateAllUserSessions(userId: String): Int = {
    val sessions = sessionStore.findByUserId(userId)
    sessions.foreach(s => sessionStore.remove(s.token))
    sessions.size
  }

  def generateApiKey(
    owner: String,
    scopes: Set[String] = Set.empty,
    expiresIn: Option[Duration] = None
  ): ApiKey = {
    val now = Instant.now()
    val apiKey = ApiKey(
      key = tokenGenerator.generateToken(32),
      secret = tokenGenerator.generateHexToken(64),
      owner = owner,
      createdAt = now,
      expiresAt = expiresIn.map(now.plus),
      scopes = scopes
    )

    apiKeyStore.save(apiKey)
    apiKey
  }

  def validateApiKey(key: String): Either[TokenServiceError, ApiKey] = {
    apiKeyStore.findByKey(key) match {
      case Some(apiKey) if !apiKey.isActive =>
        Left(ApiKeyRevoked(key))
      case Some(apiKey) if apiKey.expiresAt.exists(_.isBefore(Instant.now())) =>
        Left(ApiKeyRevoked(key))
      case Some(apiKey) =>
        Right(apiKey)
      case None =>
        Left(ApiKeyNotFound(key))
    }
  }

  def validateApiKeyWithScope(key: String, requiredScope: String): Either[TokenServiceError, ApiKey] = {
    validateApiKey(key).flatMap { apiKey =>
      if (apiKey.scopes.isEmpty || apiKey.scopes.contains(requiredScope)) {
        Right(apiKey)
      } else {
        Left(InvalidScope(requiredScope))
      }
    }
  }

  def revokeApiKey(key: String): Either[TokenServiceError, Unit] = {
    apiKeyStore.findByKey(key) match {
      case Some(_) =>
        apiKeyStore.revoke(key)
        Right(())
      case None =>
        Left(ApiKeyNotFound(key))
    }
  }

  def getOwnerApiKeys(owner: String): List[ApiKey] = {
    apiKeyStore.findByOwner(owner)
  }

  def cleanupExpiredSessions(): Int = {
    sessionStore.removeExpired()
  }
}

