  val service = TokenGenerationService(
    sessionDuration = Duration.ofHours(8),
    maxSessionsPerUser = 3
  )

  // --- Session Management ---
  println("--- Session Management ---")

  val sessionResult = service.createSession("user-001")
  sessionResult match {
    case Right(session) =>
      println(s"Created session for ${session.userId}")
      println(s"  Token: ${session.token}")
      println(s"  Created: ${session.createdAt}")
      println(s"  Expires: ${session.expiresAt}")

      // Validate the session
      service.validateSession(session.token) match {
        case Right(validSession) =>
          println(s"\n  Session validated successfully for user: ${validSession.userId}")
        case Left(error) =>
          println(s"\n  Session validation failed: $error")
      }

      // Refresh the session
      service.refreshSession(session.token) match {
        case Right(newSession) =>
          println(s"\n  Session refreshed. New token: ${newSession.token}")
          println(s"  New expiry: ${newSession.expiresAt}")

          // Old token should no longer be valid
          service.validateSession(session.token) match {
            case Left(_) => println("  Old token correctly invalidated")
            case Right(_) => println("  WARNING: Old token still valid!")
          }
        case Left(error) =>
          println(s"\n  Session refresh failed: $error")
      }

    case Left(error) =>
      println(s"Failed to create session: $error")
  }

  // Create multiple sessions for the same user
  println("\n--- Multiple Sessions ---")
  (1 to 4).foreach { i =>
    service.createSession("user-002") match {
      case Right(session) =>
        println(s"  Session $i created: ${session.token.take(8)}...")
      case Left(error) =>
        println(s"  Session $i failed: $error")
    }
  }

  val userSessions = service.invalidateAllUserSessions("user-002")
  println(s"  Invalidated $userSessions sessions for user-002")

  // --- API Key Management ---
  println("\n--- API Key Management ---")

  val apiKey = service.generateApiKey(
    owner = "app-001",
    scopes = Set("read", "write", "admin"),
    expiresIn = Some(Duration.ofDays(365))
  )
  println(s"Generated API Key:")
  println(s"  Key:     ${apiKey.key}")
  println(s"  Secret:  ${apiKey.secret}")
  println(s"  Owner:   ${apiKey.owner}")
  println(s"  Scopes:  ${apiKey.scopes.mkString(", ")}")
  println(s"  Expires: ${apiKey.expiresAt.getOrElse("Never")}")

  // Validate API key
  service.validateApiKey(apiKey.key) match {
    case Right(validKey) =>
      println(s"\n  API key validated for owner: ${validKey.owner}")
    case Left(error) =>
      println(s"\n  API key validation failed: $error")
  }

  // Validate with scope
  service.validateApiKeyWithScope(apiKey.key, "read") match {
    case Right(_) => println("  Scope 'read' authorized")
    case Left(error) => println(s"  Scope check failed: $error")
  }

  service.validateApiKeyWithScope(apiKey.key, "delete") match {
    case Right(_) => println("  Scope 'delete' authorized")
    case Left(error) => println(s"  Scope check failed: $error")
  }

  // Generate a key without scopes (all access)
  val openApiKey = service.generateApiKey(owner = "app-002")
  println(s"\n  Open API Key (no scope restrictions): ${openApiKey.key}")

  service.validateApiKeyWithScope(openApiKey.key, "anything") match {
    case Right(_) => println("  Open key passes any scope check")
    case Left(_) => println("  Unexpected scope rejection")
  }

  // Revoke an API key
  service.revokeApiKey(apiKey.key) match {
    case Right(_) =>
      println(s"\n  API key revoked: ${apiKey.key.take(8)}...")
      service.validateApiKey(apiKey.key) match {
        case Left(ApiKeyRevoked(_)) => println("  Revoked key correctly rejected")
        case other => println(s"  Unexpected result: $other")
      }
    case Left(error) =>
      println(s"\n  Revocation failed: $error")
  }

  // List owner's keys
  val ownerKeys = service.getOwnerApiKeys("app-001")
  println(s"\n  Keys for app-001: ${ownerKeys.size}")

  // --- Cleanup ---
  println("\n--- Cleanup ---")
  val cleaned = service.cleanupExpiredSessions()
  println(s"  Cleaned up $cleaned expired sessions")

  println("\n=== Demo Complete ===")
